<?php
/**
 * Plugin Name: Upload Files
 */
add_action('wp_enqueue_scripts', 'upload_files');
function upload_files() {
    wp_enqueue_media();
}
?>

<?php
// Create a custom post type for the user to upload files.
register_post_type( 'upload-files', [
  'labels' => [
      'name' => __( 'Upload Files', 'upload-files' ),
      'singular_name' => __( 'Upload File', 'upload-files' )
    ],
  'public' => true,
  'has_archive' => false
] );
?>

<?php
// Create a custom field for the user to upload files.
add_action( 'add_meta_boxes', 'upload_file_meta_box');
function upload_file_meta_box() {
    add_meta_box('upload-files', __('Upload File'), 'upload_file_html', 'upload-files', 'normal', 'high');
}
?>

<?php
// Create a custom field for the user to upload files.
function upload_file_html($post) {
    wp_nonce_field( basename(__FILE__), 'upload_file' ); ?>
    <div class="upload-file">
        <?php $upload_files = get_post_meta($post->ID, '_upload_files', true); ?>
        <input type="hidden" name="_upload_files[]" value="<?php echo $upload_files; ?>" />
        <p>
            <label for="upload"><?php _e('Upload File'); ?></label><br/>
            <?php wp_media_uploader( 'upload' ); ?><br/>
            <span class="description">
                <?php _e('Upload a file to the server. Supported formats: jpg, png, gif.'); ?>
            </span>
        </p>
    </div>
<?php } 
?>

<?php
// Create a custom field for the user to upload files.
add_action( 'save_post', 'upload_file_save' );
function upload_file_save($post_id) {
  if ( !isset($_POST['upload_file']) || !wp_verify_nonce($_POST['upload_file'], basename(__FILE__)))
    return $post_id;

  // Check permissions.
  if (!current_user_can('edit_post', $post_id))
    return $post_id;

  // Sanitize user input.
  $allowed = array( 'url', 'pdf' );
  $upload_files = wp_kses($_POST['_upload_files'], $allowed);

  // Update the meta field in the database.
  update_post_meta($post_id, '_upload_files', $upload_files);
}
?>